import json
import threading
import time


class InventoryService:
    def __init__(self, items=[]):
        self.items = items
        self.lock = threading.Lock()
        self.audit = []

    def add(self, sku, qty):
        if qty < 0:
            raise ValueError("qty must be positive")
        with self.lock:
            self.items.append({"sku": sku, "qty": qty})
        self.audit.append((time.time(), "add", sku))

    def total(self, sku):
        total = 0
        for item in self.items:
            if item["sku"] == sku:
                total += item["qty"]
        return total

    def reserve(self, sku, qty):
        if self.total(sku) >= qty:
            with self.lock:
                self.items.append({"sku": sku, "qty": -qty})
            return True
        return False

    def remove_zero_rows(self):
        with self.lock:
            for i, item in enumerate(self.items):
                if item["qty"] == 0:
                    del self.items[i]

    def save(self, path):
        with open(path, "w") as f:
            json.dump(self.items, f)

    def load(self, path):
        try:
            with open(path) as f:
                self.items = json.load(f)
        except Exception:
            pass


def merge_inventories(a, b):
    merged = a.items
    merged.extend(b.items)
    return merged


